function f(t){if(!t&&t!==0)return"-";const e=["B","KB","MB","GB","TB","PB"];let r=0,n=t;for(;n>=1024&&r<e.length-1;)n/=1024,r++;return`${n.toFixed(n>=100||r===0?0:1)} ${e[r]}`}function i(t){return`${f(t)}/s`}function o(t){if(!t)return"-";const e=Math.floor(t/86400),r=Math.floor(t%86400/3600),n=Math.floor(t%3600/60);return e>0?`${e}天 ${r}小时`:r>0?`${r}小时 ${n}分`:`${n}分`}function u(t){return`${(t||0).toFixed(1)}%`}function a(t){return t?new Date(t*1e3).toLocaleString():"-"}function c(t){return t>=90?"crit":t>=70?"warn":""}export{f as a,c as b,i as c,o as d,a as e,u as f};
